// AuthServiceServer is the server API for AuthService service.
// All implementations must embed UnimplementedAuthServiceServer
// for forward compatibility.
type AuthServiceServer interface {
	// Login for the "admin" user - root user with special privileges
	// whose credentials are stored internally in izcr
	LoginAdmin(context.Context, *LoginAdminRequest) (*LoginAdminResponse, error)
	// Login with a secret (password) - used for providers like Keycloak
	LoginWithSecret(context.Context, *LoginWithSecretRequest) (*LoginWithSecretResponse, error)
	// Login via OpenID Connect - first step in three-step process
	LoginOIDC(context.Context, *LoginOIDCRequest) (*LoginOIDCResponse, error)
	// Login with code - third step in OIDC login process
	LoginWithCode(context.Context, *LoginWithCodeRequest) (*LoginWithCodeResponse, error)
	// List all users
	ListUsers(context.Context, *ListUsersRequest) (*ListUsersResponse, error)
	// List all users as tenant admin
	ListUsersAsTenant(context.Context, *ListUsersAsTenantRequest) (*ListUsersResponse, error)
	// Create a new user
	CreateUser(context.Context, *CreateUserRequest) (*CreateUserResponse, error)
	// this is a variation of CreateUser - by for a tenant admin to be able to create a user for a tenant
	// this is the common way to create a user for a tenant (most tenant admins are not superadmin.* permissions)
	CreateUserAsTenant(context.Context, *CreateUserAsTenantRequest) (*CreateUserResponse, error)
	// Patch/update a user
	PatchUser(context.Context, *PatchUserRequest) (*PatchUserResponse, error)
	// Patch/update a user for a tenant
	PatchUserAsTenant(context.Context, *PatchUserAsTenantRequest) (*PatchUserResponse, error)
	// Delete a user (superadmin - actually deletes from system)
	DeleteUser(context.Context, *DeleteUserRequest) (*DeleteUserResponse, error)
	// Delete/remove a user from a tenant (tenant admin - removes from tenant only)
	// If user belongs to other tenants, they remain in the system.
	// If user has no other tenant memberships, they become an orphan user.
	DeleteUserAsTenant(context.Context, *DeleteUserAsTenantRequest) (*DeleteUserResponse, error)
	// Get a single user by ID or username
	GetUser(context.Context, *GetUserRequest) (*GetUserResponse, error)
	// Search users by username pattern
	SearchUsers(context.Context, *SearchUsersRequest) (*SearchUsersResponse, error)
	// Update user password
	UpdateUserPassword(context.Context, *UpdateUserPasswordRequest) (*UpdateUserPasswordResponse, error)
	// Set user system admin flag
	SetUserSysAdmin(context.Context, *SetUserSysAdminRequest) (*SetUserSysAdminResponse, error)
	// WhoAmI validates the current token and returns user information
	// Allowed for users with unvalidated email so they can check their status
	WhoAmI(context.Context, *WhoAmIRequest) (*WhoAmIResponse, error)
	// GetMyPermissions returns the effective permissions for the current authenticated user.
	// Any authenticated user can call this to see their own permissions.
	GetMyPermissions(context.Context, *GetMyPermissionsRequest) (*GetUserPermissionsResponse, error)
	// ListAuthProviders returns available authentication providers for login
	ListAuthProviders(context.Context, *ListAuthProvidersRequest) (*ListAuthProvidersResponse, error)
	// ValidateEmail validates a user's email address using a token from their email
	// This endpoint does not require authentication
	ValidateEmail(context.Context, *ValidateEmailRequest) (*ValidateEmailResponse, error)
	// ResendValidationEmail resends the email validation link to the authenticated user
	// Allowed for users with unvalidated email
	ResendValidationEmail(context.Context, *ResendValidationEmailRequest) (*ResendValidationEmailResponse, error)
	// InviteUser invites a new user by email
	// The invited user will receive an email with a validation link
	InviteUser(context.Context, *InviteUserRequest) (*InviteUserResponse, error)
	InviteUserAsTenant(context.Context, *InviteUserAsTenantRequest) (*InviteUserAsTenantResponse, error)
	// ResendInviteUser resends the invitation email to a user who hasn't accepted yet
	// Only works if last_auth_change_at is zero (user hasn't completed auth setup)
	ResendInviteUser(context.Context, *ResendInviteUserRequest) (*ResendInviteUserResponse, error)
	ResendInviteUserAsTenant(context.Context, *ResendInviteUserAsTenantRequest) (*ResendInviteUserAsTenantResponse, error)
	// AdminValidateUserEmail allows a superadmin to mark a user's email as validated
	// This is useful for testing or when email delivery is not available
	AdminValidateUserEmail(context.Context, *AdminValidateUserEmailRequest) (*AdminValidateUserEmailResponse, error)
	// SetInitialPassword sets the initial password for a newly invited user
	// Only works if last_auth_change_at is zero (user hasn't completed auth setup)
	// Uses limited JWT token (auth_setup_only=true) obtained after email validation
	SetInitialPassword(context.Context, *SetInitialPasswordRequest) (*SetInitialPasswordResponse, error)
	// RequestPasswordReset sends a password reset email to the user
	// Always returns success to prevent email enumeration attacks
	RequestPasswordReset(context.Context, *RequestPasswordResetRequest) (*RequestPasswordResetResponse, error)
	// ValidatePasswordResetToken validates a password reset token and returns a limited JWT
	// The limited JWT can be used to set a new password via SetInitialPassword
	ValidatePasswordResetToken(context.Context, *ValidatePasswordResetTokenRequest) (*ValidatePasswordResetTokenResponse, error)
	// RefreshToken generates a new JWT with updated permissions checksum.
	// This does not require re-authentication - it validates the current token
	// and returns a new token with the latest permissions.
	// Use this when receiving a 403 with error code PERMISSIONS_STALE.
	RefreshToken(context.Context, *RefreshTokenRequest) (*RefreshTokenResponse, error)
	// CheckUserPermission checks if a user has a specific permission.
	// This is an admin-only API for testing and debugging permission configurations.
	// Superadmins can check any user; tenant admins can check users in their tenant.
	CheckUserPermission(context.Context, *CheckUserPermissionRequest) (*CheckUserPermissionResponse, error)
	// GetUserPermissions retrieves all effective permissions for a user.
	// Returns both allow and deny permissions with their sources (roles, groups, direct grants).
	// Superadmins can get permissions for any user; tenant admins can get permissions for tenant users.
	GetUserPermissions(context.Context, *GetUserPermissionsRequest) (*GetUserPermissionsResponse, error)
	// TotpSetup begins TOTP enrollment. Returns secret, provisioning URI, and recovery codes.
	TotpSetup(context.Context, *TotpSetupRequest) (*TotpSetupResponse, error)
	// TotpVerifySetup verifies TOTP enrollment with the first authenticator code.
	TotpVerifySetup(context.Context, *TotpVerifySetupRequest) (*TotpVerifySetupResponse, error)
	// TotpValidate validates a TOTP code during login (second step after password).
	TotpValidate(context.Context, *TotpValidateRequest) (*TotpValidateResponse, error)
	// TotpDisable disables TOTP for the authenticated user (requires current TOTP code).
	TotpDisable(context.Context, *TotpDisableRequest) (*TotpDisableResponse, error)
	// TotpAdminReset resets TOTP for a user (admin emergency reset).
	TotpAdminReset(context.Context, *TotpAdminResetRequest) (*TotpAdminResetResponse, error)
	// TotpStatus returns TOTP status for the authenticated user.
	TotpStatus(context.Context, *TotpStatusRequest) (*TotpStatusResponse, error)
	mustEmbedUnimplementedAuthServiceServer()
}

